import boto3
import json
import time

def script_handler(events, context):
  instance_id = events['InstanceId']
  region = events['Region']
  upgrade_profile_name = events['UpgradeInstanceProfileName']
  ec2 = boto3.client('ec2', region_name=region)
  iam = boto3.client('iam')
  ssm = boto3.client('ssm', region_name=region)
  instance = ec2.describe_instances(InstanceIds=[instance_id])['Reservations'][0]['Instances'][0]
  current_profile_arn = instance.get('IamInstanceProfile', {}).get('Arn', '')
  if current_profile_arn:
    profile_name = current_profile_arn.split('/')[-1]
    has_ssm = False
    try:
      roles = iam.get_instance_profile(InstanceProfileName=profile_name)['InstanceProfile'].get('Roles', [])
      if roles:
        role_name = roles[0]['RoleName']
        attached = iam.list_attached_role_policies(RoleName=role_name)['AttachedPolicies']
        has_ssm = any('AmazonSSMManagedInstanceCore' in p['PolicyArn'] or 'AmazonEC2RoleforSSM' in p['PolicyArn'] for p in attached)
        if not has_ssm:
          all_docs = []
          for pn in iam.list_role_policies(RoleName=role_name)['PolicyNames']:
            all_docs.append(json.dumps(iam.get_role_policy(RoleName=role_name, PolicyName=pn)['PolicyDocument']).lower())
          for p in attached:
            if ':iam::' in p['PolicyArn'] and ':policy/' in p['PolicyArn']:
              try:
                pol = iam.get_policy(PolicyArn=p['PolicyArn'])
                ver = iam.get_policy_version(PolicyArn=p['PolicyArn'], VersionId=pol['Policy']['DefaultVersionId'])
                all_docs.append(json.dumps(ver['PolicyVersion']['Document']).lower())
              except: pass
          combined = ' '.join(all_docs)
          has_ssm = 'ssm:' in combined and 'ssmmessages:' in combined
    except Exception as e:
      print(f'Error checking role: {e}')
    if has_ssm:
      return {'TempProfileAttached': 'false', 'Message': 'Existing instance role has SSM permissions'}
    raise Exception(f'INCOMPATIBLE: Instance role {profile_name} lacks SSM permissions. Add AmazonSSMManagedInstanceCore to the role, or detach it so the automation can attach a temporary upgrade profile. The automation does not modify existing instance roles.')
  try:
    iam.get_instance_profile(InstanceProfileName=upgrade_profile_name)
  except:
    raise Exception(f'Upgrade profile {upgrade_profile_name} does not exist. See iam-roles.md.')
  ec2.associate_iam_instance_profile(IamInstanceProfile={'Name': upgrade_profile_name}, InstanceId=instance_id)
  print(f'Attached temporary profile: {upgrade_profile_name}')
  time.sleep(30)
  info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
  if not (info and info[0].get('PingStatus') == 'Online'):
    print('Rebooting for SSM...')
    ec2.reboot_instances(InstanceIds=[instance_id])
    for i in range(18):
      time.sleep(10)
      info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
      if info and info[0].get('PingStatus') == 'Online': break
    else:
      for a in ec2.describe_iam_instance_profile_associations(Filters=[{'Name': 'instance-id', 'Values': [instance_id]}])['IamInstanceProfileAssociations']:
        if a['State'] == 'associated': ec2.disassociate_iam_instance_profile(AssociationId=a['AssociationId'])
      raise Exception('SSM agent did not come online after attaching temporary profile; profile removed')
  return {'TempProfileAttached': 'true', 'Message': f'Attached temporary profile {upgrade_profile_name}'}

