import boto3
def script_handler(events, context):
  ec2 = boto3.client('ec2', region_name=events['Region'])
  instance = ec2.describe_instances(InstanceIds=[events['InstanceId']])['Reservations'][0]['Instances'][0]
  used = set()
  for bdm in instance.get('BlockDeviceMappings', []):
    d = bdm['DeviceName']
    used.add(d)
    used.add(d.replace('/dev/sd', '/dev/xvd') if d.startswith('/dev/sd') else d.replace('/dev/xvd', '/dev/sd'))
  for letter in 'fghijklmnop':
    if f'/dev/sd{letter}' not in used and f'/dev/xvd{letter}' not in used:
      return {'Device': f'/dev/sd{letter}'}
  raise Exception('No available device')

import boto3
import time

def script_handler(events, context):
  ssm = boto3.client('ssm', region_name=events['Region'])
  instance_id = events['InstanceId']
  info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
  if not info or info[0].get('PingStatus') != 'Online':
    return {'Result': 'UPGRADE_IN_PROGRESS'}
  try:
    cmd = ssm.send_command(InstanceIds=[instance_id], DocumentName='AWS-RunPowerShellScript', Parameters={'commands': ["$os = (Get-WmiObject Win32_OperatingSystem).Caption; $state = (Get-ItemProperty 'HKLM:\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Setup\\State' -EA SilentlyContinue).ImageState; $setup = if (Get-Process SetupHost -EA SilentlyContinue) { 'Running' } else { 'NotRunning' }; if ($state -eq 'IMAGE_STATE_UNDEPLOYABLE') { Write-Output 'FATAL' } elseif ($os -match '2019' -and $state -eq 'IMAGE_STATE_COMPLETE' -and $setup -eq 'NotRunning') { Write-Output 'UPGRADE_COMPLETE' } else { Write-Output 'UPGRADE_IN_PROGRESS' }"]})
    cmd_id = cmd['Command']['CommandId']
  except:
    return {'Result': 'UPGRADE_IN_PROGRESS'}
  for _ in range(18):
    time.sleep(5)
    try:
      r = ssm.get_command_invocation(CommandId=cmd_id, InstanceId=instance_id)
      if r['Status'] in ['Success', 'Failed']:
        out = r.get('StandardOutputContent', '')
        if 'FATAL' in out: raise Exception('IMAGE_STATE_UNDEPLOYABLE')
        if 'UPGRADE_COMPLETE' in out: return {'Result': 'UPGRADE_COMPLETE'}
        return {'Result': 'UPGRADE_IN_PROGRESS'}
    except Exception as e:
      if 'FATAL' in str(e) or 'UNDEPLOYABLE' in str(e): raise
  return {'Result': 'UPGRADE_IN_PROGRESS'}

