import boto3
import time

def script_handler(events, context):
  ssm = boto3.client('ssm', region_name=events['Region'])
  instance_id = events['InstanceId']
  for _ in range(60):
    info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
    if info and info[0].get('PingStatus') == 'Online': break
    time.sleep(5)
  else:
    raise Exception('SSM agent never came online')
  cmd = ssm.send_command(InstanceIds=[instance_id], DocumentName='AWS-RunPowerShellScript', Parameters={'commands': ["$os = (Get-WmiObject Win32_OperatingSystem).Caption; $state = (Get-ItemProperty 'HKLM:\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Setup\\State' -EA SilentlyContinue).ImageState; if ($state -eq 'IMAGE_STATE_UNDEPLOYABLE') { Write-Output 'FATAL' } elseif ($os -match '2019' -and $state -eq 'IMAGE_STATE_COMPLETE') { Write-Output 'UPGRADE_COMPLETE' } else { Write-Output 'UPGRADE_IN_PROGRESS' }"]})
  cmd_id = cmd['Command']['CommandId']
  for _ in range(24):
    time.sleep(5)
    r = ssm.get_command_invocation(CommandId=cmd_id, InstanceId=instance_id)
    if r['Status'] in ['Success', 'Failed']:
      out = r.get('StandardOutputContent', '')
      if 'FATAL' in out: raise Exception('IMAGE_STATE_UNDEPLOYABLE')
      if 'UPGRADE_COMPLETE' in out: return {'Result': 'UPGRADE_COMPLETE'}
      raise Exception(f'Upgrade not complete: {out}')
  raise Exception('Verify command timed out')

import boto3
import time
def script_handler(events, context):
  ec2 = boto3.client('ec2', region_name=events['Region'])
  try:
    ec2.detach_volume(VolumeId=events['VolumeId'], Force=True)
    for _ in range(24):
      if ec2.describe_volumes(VolumeIds=[events['VolumeId']])['Volumes'][0]['State'] == 'available': break
      time.sleep(5)
  except: pass
  try: ec2.delete_volume(VolumeId=events['VolumeId'])
  except: pass
  return {'Message': 'Cleaned up'}

import boto3
import time

def script_handler(events, context):
  ssm = boto3.client('ssm', region_name=events['Region'])
  instance_id = events['InstanceId']
  print('Waiting for reboot to initiate...')
  for i in range(30):
    time.sleep(5)
    info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
    if not info or info[0].get('PingStatus') != 'Online':
      print(f'Agent went offline after {(i+1)*5}s')
      break
  else:
    print('Agent never went offline - reboot may have already completed')
  print('Waiting for SSM agent to come back online...')
  for i in range(60):
    time.sleep(5)
    info = ssm.describe_instance_information(Filters=[{'Key': 'InstanceIds', 'Values': [instance_id]}])['InstanceInformationList']
    if info and info[0].get('PingStatus') == 'Online':
      print(f'Agent back online after {(i+1)*5}s')
      return {'Status': 'Online'}
  raise Exception('SSM agent did not come back online after pinned update reboot')

