def script_handler(events, context):
  if events['TempProfileAttached'] == 'true':
    ec2 = boto3.client('ec2', region_name=events['Region'])
    for a in ec2.describe_iam_instance_profile_associations(Filters=[{'Name': 'instance-id', 'Values': [events['InstanceId']]}])['IamInstanceProfileAssociations']:
